import{_ as r,o,c as t,a5 as a}from"./chunks/framework.C3rn-ehA.js";const u=JSON.parse('{"title":"OpenSSF Scorecard","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security/scorecard.md","filePath":"reference/security/scorecard.md"}'),s={name:"reference/security/scorecard.md"};function i(c,e,d,l,n,h){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="openssf-scorecard" tabindex="-1">OpenSSF Scorecard <a class="header-anchor" href="#openssf-scorecard" aria-label="Permalink to &quot;OpenSSF Scorecard&quot;">​</a></h1><h2 id="what-it-is" tabindex="-1">What it is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What it is&quot;">​</a></h2><p><a href="https://scorecard.dev" target="_blank" rel="noreferrer">OpenSSF Scorecard</a> is an automated tool from the Open Source Security Foundation (OpenSSF) that assesses repositories against a set of <a href="https://github.com/ossf/scorecard/blob/main/docs/checks.md" target="_blank" rel="noreferrer">security best-practice checks</a> and assigns each a score of 0–10. Unlike vulnerability scanners that flag specific CVEs, Scorecard evaluates the project&#39;s <strong>security posture</strong> - whether the repository is configured to prevent vulnerabilities from being introduced in the first place.</p><h2 id="why-platform-mesh-uses-it" tabindex="-1">Why Platform Mesh uses it <a class="header-anchor" href="#why-platform-mesh-uses-it" aria-label="Permalink to &quot;Why Platform Mesh uses it&quot;">​</a></h2><p>Scorecard gives Platform Mesh continuous, public posture monitoring:</p><ul><li><strong>Surfaces regressions</strong> - runs on every push to <code>main</code> and weekly, so policy drift is caught quickly rather than discovered in a security audit.</li><li><strong>Public visibility</strong> - results are published to <code>scorecard.dev</code> and linked via a per-repo badge, so adopters can verify the project&#39;s security hygiene without having to audit the repositories themselves.</li><li><strong>Complements other tools</strong> - Renovate handles automated dependency updates and the Scorecard verifies that the surrounding process (branch protection, code review, signed artifacts, and so on) is in good shape.</li></ul><h2 id="how-it-is-configured" tabindex="-1">How it is configured <a class="header-anchor" href="#how-it-is-configured" aria-label="Permalink to &quot;How it is configured&quot;">​</a></h2><p>Platform Mesh uses a reusable workflow defined in <a href="https://github.com/platform-mesh/.github" target="_blank" rel="noreferrer"><code>platform-mesh/.github</code></a>: <code>platform-mesh/.github/.github/workflows/job-ossf-scorecard.yml</code>.</p><p>Each participating repository calls it from its own caller workflow. In this repository the caller is <a href="https://github.com/platform-mesh/platform-mesh.github.io/blob/main/.github/workflows/ossf-scorecard.yml" target="_blank" rel="noreferrer"><code>.github/workflows/ossf-scorecard.yml</code></a>. It triggers on:</p><ul><li>Push to <code>main</code></li><li>Weekly cron (Mondays at 04:30 UTC)</li><li>Manual <code>workflow_dispatch</code></li></ul><h2 id="which-repositories-are-scored" tabindex="-1">Which repositories are scored <a class="header-anchor" href="#which-repositories-are-scored" aria-label="Permalink to &quot;Which repositories are scored&quot;">​</a></h2><p>Scorecard is applied to the repositories that ship the Platform Mesh product - core services and operators, shared libraries, and shipped artifacts - as well as repositories that adopters depend on directly:</p><ul><li><code>security-operator</code>, <code>account-operator</code>, <code>platform-mesh-operator</code>, <code>extension-manager-operator</code></li><li><code>iam-service</code>, <code>iam-ui</code>, <code>kubernetes-graphql-gateway</code>, <code>portal</code>, <code>resource-broker</code></li><li><code>virtual-workspaces</code>, <code>rebac-authz-webhook</code></li><li><code>golang-commons</code>, <code>subroutines</code>, <code>portal-server-lib</code>, <code>portal-ui-lib</code></li><li><code>helm-charts</code>, <code>custom-images</code>, <code>upstream-images</code></li><li><code>provider-quickstart</code>, <code>ocm</code>, <code>platform-mesh.github.io</code></li><li><code>platform-mesh/.github</code></li></ul><p>Samples, templates, PoCs, and meta repositories (for example <code>backlog</code>, <code>architecture</code>, <code>community</code>) are intentionally excluded. Applying Scorecard to repositories that have no releases, no shipped binaries, or are meant to be copied rather than depended on produces misleading low scores on checks that do not apply. See the discussion on <a href="https://github.com/platform-mesh/backlog/issues/227" target="_blank" rel="noreferrer">backlog#227</a> for the full rationale and the canonical list.</p><h2 id="where-to-see-results" tabindex="-1">Where to see results <a class="header-anchor" href="#where-to-see-results" aria-label="Permalink to &quot;Where to see results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Location</th><th>What you see</th></tr></thead><tbody><tr><td>Repository <code>README.md</code></td><td>Badge linking to the public Scorecard viewer for that repo</td></tr><tr><td><a href="https://scorecard.dev/viewer/?uri=github.com/platform-mesh/platform-mesh.github.io" target="_blank" rel="noreferrer">scorecard.dev viewer</a></td><td>Detailed breakdown of every check, with pass/fail and a short explanation</td></tr><tr><td>GitHub <strong>Security</strong> tab → Code scanning</td><td>SARIF results uploaded after each run; visible to org members</td></tr></tbody></table><h2 id="how-to-interpret-scores" tabindex="-1">How to interpret scores <a class="header-anchor" href="#how-to-interpret-scores" aria-label="Permalink to &quot;How to interpret scores&quot;">​</a></h2><p>Each check is scored independently and the overall score is a weighted average from 0 (worst) to 10 (best). The <a href="https://github.com/ossf/scorecard/blob/main/docs/checks.md" target="_blank" rel="noreferrer">OpenSSF checks documentation</a> explains what each check measures and how to improve it. A score of 7 or higher is generally considered a healthy posture for an actively maintained open-source project. If a check is failing, the Scorecard viewer shows the specific reason and links to remediation guidance.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./">Security overview</a></li><li><a href="https://scorecard.dev" target="_blank" rel="noreferrer">OpenSSF Scorecard</a></li><li><a href="https://github.com/ossf/scorecard/blob/main/docs/checks.md" target="_blank" rel="noreferrer">OpenSSF checks documentation</a></li><li><a href="https://github.com/platform-mesh/.github" target="_blank" rel="noreferrer">Platform Mesh <code>.github</code> repository</a></li></ul>',20)])])}const m=r(s,[["render",i]]);export{u as __pageData,m as default};
